#include<bits/stdc++.h>
using namespace std;
struct Tree {
	char l, r;
} a[1001];
char b, c;

void dfs(char x) {
	if (x == '*')
		return;
	cout << x;
	dfs(a[x].l);
	dfs(a[x].r);
}
int main() {
	int n;
	cin >> n;
	cin >> c;
	cin >> a[c].l;
	cin >> a[c].r;
	for (int i = 2; i <= n; i++) {
		cin >> b;
		cin >> a[b].l;
		cin >> a[b].r;
	}
	dfs(c);
	return 0;
}
